function LFightIdleForwardAction:OnRun(time)
	local pos = self._obj:GetPosition()
	local passTime = Time.deltaTime
	if passTime > 1 then
		return
	end
	local x = pos.x + self._obj:GetMoveSpeed() * 0.01 * Time.deltaTime
	if pos.x ~= x then
		pos.x = x
		self._obj:SetPosition(pos)
	end
end
